#include <stdio.h>
#include <stdlib.h>

int cmpInt(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int maxContentChildren(int *g, int gSize, int *s, int sSize) {
    qsort(g, gSize, sizeof(int), cmpInt);
    qsort(s, sSize, sizeof(int), cmpInt);
    int i = 0, j = 0;
    while (i < gSize && j < sSize) {
        if (s[j] >= g[i]) {
            i++;
        }
        j++;
    }
    return i;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *g = (int *)malloc(n * sizeof(int));
        int *s = (int *)malloc(m * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &g[i]);
        for (int i = 0; i < m; ++i) scanf("%d", &s[i]);
        printf("%d\n", maxContentChildren(g, n, s, m));
        free(g);
        free(s);
    }
    return 0;
}

