#include <bits/stdc++.h>
using namespace std;

int maxContentChildren(vector<int> &g, vector<int> &s) {
    sort(g.begin(), g.end());
    sort(s.begin(), s.end());
    int i = 0, j = 0;
    while (i < (int)g.size() && j < (int)s.size()) {
        if (s[j] >= g[i]) ++i;
        ++j;
    }
    return i;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int n, m; cin >> n >> m;
        vector<int> g(n), s(m);
        for (int &x : g) cin >> x;
        for (int &x : s) cin >> x;
        cout << maxContentChildren(g, s) << '\n';
    }
    return 0;
}

