import java.io.*;
import java.util.*;

public class Main {
    private static int maxContentChildren(int[] g, int[] s) {
        Arrays.sort(g);
        Arrays.sort(s);
        int i = 0, j = 0;
        while (i < g.length && j < s.length) {
            if (s[j] >= g[i]) i++;
            j++;
        }
        return i;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            int[] g = new int[n];
            int[] s = new int[m];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; i++) g[i] = Integer.parseInt(st.nextToken());
            if (m > 0) {
                st = new StringTokenizer(br.readLine());
                for (int i = 0; i < m; i++) s[i] = Integer.parseInt(st.nextToken());
            } else {
                // consume the (possibly empty) line for cookies
                br.readLine();
            }
            sb.append(maxContentChildren(g, s)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

